// V5.3: Clasificacion heuristica local
const body = $json.body ?? $json;
const binaryData = $binary ?? {};
const image = binaryData.image ?? null;

const query = String(body.query ?? body.pregunta ?? '').trim().slice(0, 2000);
const sessionId = String(body.sessionId ?? body.session_id ?? 'default').replace(/[^a-zA-Z0-9_-]/g, '').slice(0, 100);
const userName = String(body.userName ?? body.user_name ?? 'Usuario').slice(0, 100);
const userEmail = String(body.userEmail ?? body.user_email ?? 'no-email@satcomla.com').slice(0, 200);
const base = ['publica', 'privada'].includes(body.base) ? body.base : 'privada';

if (!query && !image) {
  throw new Error('Query vacia y sin imagen adjunta');
}

const querySearch = query || 'consulta visual';

return [{
  json: {
    query,
    querySearch,
    sessionId,
    userName,
    userEmail,
    base,
    hasImage: !!image,
    imageMimeType: image?.mimeType ?? null,
    imageData: image?.data ?? null
  }
}];

