// V5.3-fix2: filtra logos/decorativos; prioriza diagramas informativos
const embeddingData = $('Generar_Embedding').first().json;
const imageItems = $input.all()
  .map(i => i.json)
  .filter(r =>
    r && r.id &&
    r.type === 'image' &&
    r.metadata?.image_url &&
    r.metadata?.image_description &&
    r.metadata.image_description.length > 80
  );

// Separar imágenes informativas (diagramas, capturas) de decorativas (logos, iconos)
const logoPatterns = /\b(logotipo|logo\b|icono\b|marca\b|brand)/i;
const informative = imageItems.filter(r => !logoPatterns.test(r.metadata.image_description));
const fallback = imageItems;

// Usar informativas si hay, sino fallback a todas
const pool = informative.length > 0 ? informative : fallback;
pool.sort((a, b) => (b.similarity || 0) - (a.similarity || 0));

const topImageUrl = pool[0]?.metadata?.image_url || null;
const relevantImages = pool.map(img => ({
  url: img.metadata.image_url,
  description: (img.metadata.image_description || '').substring(0, 200),
  article_title: img.metadata.article_title || null,
  similarity: img.similarity || 0
}));

return [{ json: {
  ...embeddingData,
  top_image_url: topImageUrl,
  relevant_images: relevantImages
} }];

