// V5.3-fix: incluye relevant_images del nodo Unify
const results = $input.all().map(i => i.json).filter(r => r && r.id);
const input = $('Validar_Clasificar').item.json;

const MIN_CONTENT = 50;
const meaningful = results.filter(r => {
  const content = (r.content || '').trim();
  return content.length >= MIN_CONTENT && r.type !== 'image';
});

const topImageUrl = $('Unify').first().json.top_image_url || null;
const relevantImages = $('Unify').first().json.relevant_images || [];

const skipReranker = meaningful.length < 4;

if (meaningful.length === 0) {
  return [{ json: {
    allResults: results,
    meaningfulResults: [],
    skipReranker: true,
    reranker_prompt: null,
    noResults: true,
    top_image_url: topImageUrl,
    relevant_images: relevantImages,
    ...input
  } }];
}

if (skipReranker) {
  return [{ json: {
    allResults: results,
    meaningfulResults: meaningful,
    skipReranker: true,
    reranker_prompt: null,
    noResults: false,
    top_image_url: topImageUrl,
    relevant_images: relevantImages,
    ...input
  } }];
}

const summaries = meaningful.map((r, i) => {
  const manual = r.metadata?.manual_name || r.metadata?.collection_name || '';
  const article = r.metadata?.article_title || '';
  const content = (r.content || '').trim().substring(0, 250);
  return `[${i}]${manual ? ' Manual: ' + manual : ''}${article ? ' | Articulo: ' + article : ''}\n${content}`;
}).join('\n\n');

return [{ json: {
  allResults: results,
  meaningfulResults: meaningful,
  skipReranker: false,
  noResults: false,
  top_image_url: topImageUrl,
  relevant_images: relevantImages,
  ...input
} }];

